public void mouseUp(MouseEvent e, int x, int y) {
    if (e.isPopupTrigger()) {
        Figure figure = computeFigureForPopup(e);
        if (figure != null) {
            showPopupMenu(figure, e.getX(), e.getY(), e.getComponent());
        }
    }
    else if (e.getClickCount() == 2) {
        handleMouseDoubleClick(e, x, y);
    }
    else {
        super.mouseUp(e, x, y);
        handleMouseUp(e, x, y);
        handleMouseClick(e, x, y);
    }
}

private Figure computeFigureForPopup(MouseEvent e) {
    Figure figure = drawing().findFigure(e.getX(), e.getY());
    if (figure != null) {
        Object attribute = figure.getAttribute(Figure.POPUP_MENU);
        if (attribute == null) {
            figure = drawing().findFigureInside(e.getX(), e.getY());
        }
    }
    return figure;
}

